import './App.css';
import {BrowserRouter , Routes , Route} from 'react-router-dom';
import Home from './pages/home';
import EditorPage from './pages/EditorPage';


function App() {
  return (
    <>
    <BrowserRouter>
    <Routes>
      <Route path="/" element = {<Home/>}></Route>
    </Routes>
    </BrowserRouter>
    </>
  );
}

export default App;
